 13→class BodyLimitPlugin {
 14→  maxBodySize;
 15→  constructor(options) {
 16→    this.maxBodySize = options.maxBodySize;
 17→  }
 18→  initRuntimeAdapter(options) {
 19→    options.adapterInterceptors ??= [];
 20→    options.adapterInterceptors.push(async (options2) => {
 21→      if (!options2.request.body) {
 22→        return options2.next();
 23→      }
 24→      let currentBodySize = 0;
 25→      const rawReader = options2.request.body.getReader();
 26→      const reader = new ReadableStream({
 27→        start: async (controller) => {
 28→          try {
 29→            if (Number(options2.request.headers.get("content-length")) > this.maxBodySize) {
 30→              controller.error(new ORPCError("PAYLOAD_TOO_LARGE"));
 31→              return;
 32→            }
 33→            while (true) {
 34→              const { done, value } = await rawReader.read();
 35→              if (done) {
 36→                break;
